import React, { useState, useEffect } from 'react';
import {
  Users, UserCircle, Stethoscope, Search, FileText, Trash2, Lock,
  Beaker, Pill, ShoppingBag, CheckCircle2, Activity, ReceiptIndianRupee, LogOut
} from 'lucide-react';

const DEPARTMENTS = [
  { id: 'CARD', name: 'Cardiology' }, { id: 'GYN', name: 'Gynecology' },
  { id: 'OPH', name: 'Ophthalmology' }, { id: 'PED', name: 'Pediatrics' },
  { id: 'ORTHO', name: 'Orthopedics' }, { id: 'DERM', name: 'Dermatology' },
  { id: 'NEURO', name: 'Neurology' }, { id: 'ENT', name: 'ENT' },
  { id: 'DENT', name: 'Dental' }, { id: 'GEN', name: 'General Medicine' }
];

const WAIT_PER_PATIENT = 20;

const LoginView = ({ handleLogin, loginForm, setLoginForm, view }) => (
  <div className="flex items-center justify-center mt-20">
    <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 w-full max-w-md">
      <div className="flex justify-center mb-6 text-blue-600"><Lock size={48} /></div>
      <h2 className="text-2xl font-black text-center mb-6 uppercase tracking-tight">
        {view} Login
      </h2>
      <form onSubmit={handleLogin} className="space-y-4">
        <input
          required
          placeholder="Username"
          value={loginForm.username}
          className="w-full p-4 border rounded-2xl bg-slate-50 outline-none focus:ring-2 ring-blue-500"
          onChange={e => setLoginForm({ ...loginForm, username: e.target.value })}
        />
        <input
          required
          type="password"
          placeholder="Password"
          value={loginForm.password}
          className="w-full p-4 border rounded-2xl bg-slate-50 outline-none focus:ring-2 ring-blue-500"
          onChange={e => setLoginForm({ ...loginForm, password: e.target.value })}
        />
        <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black hover:bg-blue-700 transition shadow-lg">Access Dashboard</button>
      </form>
    </div>
  </div>
);

export default function SmartHospital() {
  const [view, setView] = useState('patient');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });

  const [patients, setPatients] = useState(() => JSON.parse(localStorage.getItem('hospital_patients')) || []);
  const [serving, setServing] = useState(() => JSON.parse(localStorage.getItem('hospital_serving')) || DEPARTMENTS.reduce((a, d) => ({ ...a, [d.id]: 0 }), {}));
  const [deptTokenCounters, setDeptTokenCounters] = useState(() => JSON.parse(localStorage.getItem('hospital_counters')) || DEPARTMENTS.reduce((a, d) => ({ ...a, [d.id]: 1 }), {}));
  const [labRequests, setLabRequests] = useState(() => JSON.parse(localStorage.getItem('hospital_lab')) || []);
  const [prescriptions, setPrescriptions] = useState(() => JSON.parse(localStorage.getItem('hospital_prescriptions')) || []);

  const [formData, setFormData] = useState({ name: '', phone: '', age: '', gender: 'Male', address: '', complaint: '', deptId: 'CARD', bp: '', temp: '' });
  const [searchToken, setSearchToken] = useState('');
  const [labInputs, setLabInputs] = useState({});
  const [medInputs, setMedInputs] = useState({});

  useEffect(() => { localStorage.setItem('hospital_patients', JSON.stringify(patients)); }, [patients]);
  useEffect(() => { localStorage.setItem('hospital_serving', JSON.stringify(serving)); }, [serving]);
  useEffect(() => { localStorage.setItem('hospital_counters', JSON.stringify(deptTokenCounters)); }, [deptTokenCounters]);
  useEffect(() => { localStorage.setItem('hospital_lab', JSON.stringify(labRequests)); }, [labRequests]);
  useEffect(() => { localStorage.setItem('hospital_prescriptions', JSON.stringify(prescriptions)); }, [prescriptions]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (loginForm.username === 'harisai' && loginForm.password === 'harisai@1234') {
      setIsAuthenticated(true);
    } else {
      alert("Invalid Credentials!");
    }
  };

  const logout = () => {
    setIsAuthenticated(false);
    setView('patient');
    setLoginForm({ username: '', password: '' });
  };

  const registerPatient = (e) => {
    e.preventDefault();
    const tokenNumber = deptTokenCounters[formData.deptId];
    const displayToken = `${formData.deptId}-${tokenNumber}`;
    const newToken = {
      displayToken,
      tokenNumber,
      ...formData,
      status: 'Waiting',
      timeJoined: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setPatients([...patients, newToken]);
    setDeptTokenCounters(prev => ({ ...prev, [formData.deptId]: prev[formData.deptId] + 1 }));
    setFormData({ name: '', phone: '', age: '', gender: 'Male', address: '', complaint: '', deptId: 'CARD', bp: '', temp: '' });
    alert(`Token issued: ${displayToken}`);
  };

  const nextPatient = (dId) => {
    const nextTokenNum = serving[dId] + 1;
    if (patients.some(p => p.deptId === dId && p.tokenNumber === nextTokenNum)) {
      setServing(prev => ({ ...prev, [dId]: nextTokenNum }));
      setLabInputs(prev => ({ ...prev, [dId]: '' }));
      setMedInputs(prev => ({ ...prev, [dId]: '' }));
    } else {
      alert(`No more patients in queue for ${dId}`);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-20">
      <nav className="bg-white shadow-sm p-4 flex justify-center gap-2 md:gap-4 border-b sticky top-0 z-50 flex-wrap">
        {[
          { id: 'doctor', icon: <Stethoscope size={18} />, label: 'Doctors' },
          { id: 'manager', icon: <Users size={18} />, label: 'Staff' },
          { id: 'lab', icon: <Beaker size={18} />, label: 'Lab' },
          { id: 'pharmacy', icon: <Pill size={18} />, label: 'Pharmacy' },
          { id: 'billing', icon: <ReceiptIndianRupee size={18} />, label: 'Billing' },
          { id: 'patient', icon: <UserCircle size={18} />, label: 'Tracker' },
        ].map(btn => (
          <button
            key={btn.id}
            onClick={() => { setView(btn.id); setIsAuthenticated(false); }}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl transition font-bold ${view === btn.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            {btn.icon} <span className="hidden sm:inline">{btn.label}</span>
          </button>
        ))}
        {isAuthenticated && (
          <button onClick={logout} className="flex items-center gap-2 text-red-500 font-bold border-l pl-4 hover:bg-red-50 px-3 rounded-xl">
            <LogOut size={18} /> <span className="hidden sm:inline">Logout</span>
          </button>
        )}
      </nav>

      <main className="p-6 max-w-7xl mx-auto">
        {(view !== 'patient' && view !== 'billing') && !isAuthenticated ? (
          <LoginView handleLogin={handleLogin} loginForm={loginForm} setLoginForm={setLoginForm} view={view} />
        ) : (
          <>
            {/* DOCTOR VIEW WITH PATIENT DETAILS */}
            {view === 'doctor' && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {DEPARTMENTS.map(d => {
                  const currentPatient = patients.find(p => p.deptId === d.id && p.tokenNumber === serving[d.id]);
                  return (
                    <div key={d.id} className="bg-white p-6 rounded-[2rem] border shadow-sm flex flex-col">
                      <div className="flex justify-between items-center mb-4">
                        <h3 className="font-black text-xl">{d.name}</h3>
                        <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold">
                          {patients.filter(p => p.deptId === d.id && p.tokenNumber > serving[d.id]).length} in queue
                        </span>
                      </div>

                      <div className="text-center py-4 bg-slate-900 text-white rounded-2xl mb-4">
                        <p className="text-[10px] opacity-50 uppercase font-black">Currently Calling</p>
                        <p className="text-4xl font-black">{d.id}-{serving[d.id]}</p>
                      </div>

                      {currentPatient && (
                        <div className="bg-blue-50/50 p-4 rounded-2xl mb-4 border border-blue-100">
                          <p className="text-sm font-black text-blue-800 uppercase mb-2">Patient Info</p>
                          <p className="text-lg font-bold">{currentPatient.name} ({currentPatient.age}y)</p>
                          <p className="text-sm text-slate-600 italic mb-2">"{currentPatient.complaint}"</p>
                          <div className="flex gap-4 text-xs font-bold text-slate-500">
                            <span className="flex items-center gap-1"><Activity size={12} /> BP: {currentPatient.bp || '--'}</span>
                            <span>TEMP: {currentPatient.temp || '--'}°F</span>
                          </div>
                        </div>
                      )}

                      <div className="space-y-2 mb-4">
                        <input placeholder="Prescribe Tests..." value={labInputs[d.id] || ''} onChange={e => setLabInputs({ ...labInputs, [d.id]: e.target.value })} className="w-full border rounded-xl px-4 py-3 bg-slate-50 text-sm outline-none focus:ring-2 ring-blue-500" />
                        <input placeholder="Prescribe Medicines..." value={medInputs[d.id] || ''} onChange={e => setMedInputs({ ...medInputs, [d.id]: e.target.value })} className="w-full border rounded-xl px-4 py-3 bg-slate-50 text-sm outline-none focus:ring-2 ring-emerald-500" />
                      </div>

                      <div className="grid grid-cols-2 gap-2">
                        <button onClick={() => nextPatient(d.id)} className="bg-slate-800 text-white py-3 rounded-xl font-bold hover:bg-black transition">Next</button>
                        <button onClick={() => alert("Details Saved!")} className="bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 transition">Save</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* STAFF / MANAGER VIEW */}
            {view === 'manager' && (
              <div className="grid lg:grid-cols-5 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 h-fit">
                  <h2 className="text-2xl font-black mb-6">OPD Registration</h2>
                  <form onSubmit={registerPatient} className="space-y-4">
                    <input required value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} placeholder="Full Name" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                    <div className="grid grid-cols-2 gap-4">
                      <input required value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} placeholder="Phone" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                      <input required value={formData.age} onChange={e => setFormData({ ...formData, age: e.target.value })} placeholder="Age" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <input value={formData.bp} onChange={e => setFormData({ ...formData, bp: e.target.value })} placeholder="Vitals: BP" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                      <input value={formData.temp} onChange={e => setFormData({ ...formData, temp: e.target.value })} placeholder="Vitals: Temp" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                    </div>
                    <select value={formData.deptId} onChange={e => setFormData({ ...formData, deptId: e.target.value })} className="w-full p-4 border rounded-2xl bg-slate-50 outline-none">
                      {DEPARTMENTS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                    </select>
                    <textarea required value={formData.complaint} onChange={e => setFormData({ ...formData, complaint: e.target.value })} placeholder="Chief Complaint" rows="2" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none"></textarea>
                    <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-blue-700">Issue Token</button>
                  </form>
                </div>

                <div className="lg:col-span-3 space-y-4">
                  <div className="flex justify-between items-center bg-white p-4 rounded-2xl border">
                    <div>
                      <p className="text-xs font-bold text-slate-400">TOTAL TODAY</p>
                      <p className="text-2xl font-black">{patients.length}</p>
                    </div>
                    <button onClick={() => { if (window.confirm("Clear all?")) setPatients([]) }} className="text-red-500 hover:bg-red-50 p-2 rounded-lg transition"><Trash2 size={20} /></button>
                  </div>
                  <div className="max-h-[500px] overflow-y-auto space-y-3 pr-2">
                    {patients.slice().reverse().map(p => (
                      <div key={p.displayToken} className="bg-white p-5 rounded-3xl border shadow-sm flex justify-between items-center">
                        <div><p className="text-xl font-black text-blue-600">{p.displayToken}</p><p className="font-bold text-slate-800">{p.name}</p></div>
                        <span className="bg-slate-100 px-4 py-2 rounded-full text-[10px] font-black text-slate-500 uppercase">{p.deptId}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}



            {/* PATIENT QUEUE TRACKER */}
            {view === 'patient' && (
              <div className="max-w-xl mx-auto text-center mt-12">
                <h1 className="text-5xl font-black text-slate-900 mb-10 tracking-tighter">Live Queue</h1>
                <div className="relative mb-12">
                  <input type="text" onChange={(e) => setSearchToken(e.target.value.toUpperCase())} placeholder="Enter Token (e.g. CARD-1)" className="w-full p-6 pl-16 border-2 border-slate-200 rounded-3xl text-2xl font-black focus:border-blue-500 outline-none uppercase shadow-sm" />
                  <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={32} />
                </div>
                {searchToken && patients.find(p => p.displayToken === searchToken) ? (
                  (() => {
                    const p = patients.find(p => p.displayToken === searchToken);
                    const opsAhead = p.tokenNumber - serving[p.deptId];
                    const waitTimeMins = opsAhead * WAIT_PER_PATIENT;
                    return opsAhead > 0 ? (
                      <div className="bg-white p-10 rounded-[3rem] shadow-2xl border">
                        <p className="text-blue-600 uppercase font-black mb-4">{DEPARTMENTS.find(d => d.id === p.deptId).name}</p>
                        <div className="flex justify-around items-center mb-8">
                          <div><p className="text-xs text-slate-400 font-bold mb-1">CURRENTLY AT</p><p className="text-5xl font-black">{p.deptId}-{serving[p.deptId]}</p></div>
                          <div className="w-px h-12 bg-slate-100"></div>
                          <div><p className="text-xs text-slate-400 font-bold mb-1">YOUR TOKEN</p><p className="text-5xl font-black text-blue-600">{p.displayToken}</p></div>
                        </div>
                        <div className="grid grid-cols-2 gap-4 pt-6 border-t">
                          <div className="bg-blue-50 p-4 rounded-2xl"><p className="font-black text-2xl">~{waitTimeMins}m</p><p className="text-[10px] text-blue-400 font-bold">EST. WAIT</p></div>
                          <div className="bg-slate-50 p-4 rounded-2xl"><p className="font-black text-2xl">{opsAhead}</p><p className="text-[10px] text-slate-400 font-bold">PEOPLE AHEAD</p></div>
                        </div>
                      </div>
                    ) : <div className="bg-emerald-600 text-white p-12 rounded-[3rem] text-3xl font-black shadow-xl animate-pulse">IT'S YOUR TURN! PLEASE PROCEED</div>;
                  })()
                ) : searchToken ? <p className="text-slate-400 font-bold">Token not found in today's list.</p> : null}
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}
